    // Since each element can be in A, B, or C, we can represent the state with two bits per element
    // However, with n up to 19, this is not feasible (2^38 possibilities)
    // So we need a smarter approach

    // Alternative approach: since n is small (<=19), we can try all possible splits into A, B, C
    // But 3^19 is still too large (~1.16 billion)
    // So we need to find a better way

    // Another observation: the optimal solution likely has small A and C (since XOR and AND are sensitive to single elements)
    // So we can try all possible small subsets for A and C, and the rest goes to B

    // Let's try all possible non-empty A and C, and the rest is B
    // But even this is O(2^n * 2^n) which is too slow for n=19

    // Given the constraints, perhaps the optimal solution is to have A and C as single elements, and B as the rest
    // Let's test this hypothesis

    // Case 1: A and C are single elements, B is the rest
    for (let i = 0; i < n; i++) {
        for (let j = 0; j < n; j++) {
            if (i === j) continue;
            const xorA = nums[i];
            let andB = ~0;
            for (let k = 0; k < n; k++) {
                if (k !== i && k !== j) {
                    andB &= nums[k];
                }
            }
            const xorC = nums[j];
            const currentSum = xorA + andB + xorC;
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    // Case 2: A is single element, B is empty, C is the rest
    for (let i = 0; i < n; i++) {
        const xorA = nums[i];
