        let xorC = 0;
        for (let j = 0; j < n; j++) {
            if (j !== i) {
                xorC ^= nums[j];
            }
        }
        const currentSum = xorA + andB + xorC;
        if (currentSum > maxSum) {
            maxSum = currentSum;
