    for (let i = 0; i < n; i++) {
        let xorA = 0;
        const andB = 0;
        const xorC = nums[i];
        for (let j = 0; j < n; j++) {
            if (j !== i) {
                xorA ^= nums[j];
            }
        }
        const currentSum = xorA + andB + xorC;
        if (currentSum > maxSum) {
            maxSum = currentSum;
        }
    }

    // Case 4: B is single element, A and C are the rest (split in all possible ways)
    for (let i = 0; i < n; i++) {
        const andB = nums[i];
        // Now split the remaining elements into A and C
        const remaining = [];
        for (let j = 0; j < n; j++) {
            if (j !== i) {
                remaining.push(nums[j]);
            }
        }
        const m = remaining.length;
        // Try all possible subsets of remaining for A, the rest goes to C
        for (let mask = 0; mask < (1 << m); mask++) {
            let xorA = 0;
            let xorC = 0;
            for (let j = 0; j < m; j++) {
                if (mask & (1 << j)) {
                    xorA ^= remaining[j];
                } else {
                    xorC ^= remaining[j];
                }
            }
            const currentSum = xorA + andB + xorC;
            if (currentSum > maxSum) {
                maxSum = currentSum;
            }
        }
    }

    // Case 5: A, B, or C is empty (handled in previous cases)

    return maxSum;
